  const findCars = () => { if (!pickup.trim() || !drop.trim()) { alert(c.missingRoute); return; } setVehicleId(null); setQuotes({}); setLoading(true); setTimeout(async () => { setLoading(false); setStep(2); await loadQuotes(); }, 900); };
